import{_ as a,o as s,c as e,ag as p}from"./chunks/framework.DU5ARZ07.js";const u=JSON.parse('{"title":"KubeVirt 系統架構概述","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/overview.md","filePath":"architecture/overview.md","lastUpdated":1774974870000}'),t={name:"architecture/overview.md"};function l(i,n,r,c,o,d){return s(),e("div",null,[...n[0]||(n[0]=[p(`<h1 id="kubevirt-系統架構概述" tabindex="-1">KubeVirt 系統架構概述 <a class="header-anchor" href="#kubevirt-系統架構概述" aria-label="Permalink to &quot;KubeVirt 系統架構概述&quot;">​</a></h1><p>KubeVirt 是一個基於 <strong>Kubernetes 的虛擬機器管理擴充套件</strong>，讓使用者可以在現有的 Kubernetes 叢集中，像管理容器一樣管理虛擬機器 (VM)。</p><h2 id="設計理念" tabindex="-1">設計理念 <a class="header-anchor" href="#設計理念" aria-label="Permalink to &quot;設計理念&quot;">​</a></h2><h3 id="核心原則-擴展而非取代" tabindex="-1">核心原則：擴展而非取代 <a class="header-anchor" href="#核心原則-擴展而非取代" aria-label="Permalink to &quot;核心原則：擴展而非取代&quot;">​</a></h3><p>KubeVirt 並不試圖取代 Kubernetes，而是<strong>完全融入</strong> Kubernetes 的生態系統。它透過以下三件事為叢集加入虛擬化能力：</p><ol><li><strong>Custom Resource Definitions (CRD)</strong> — 新增 VM 相關資源型別到 Kubernetes API</li><li><strong>Controllers</strong> — 叢集級別的控制邏輯 (virt-controller)</li><li><strong>DaemonSet</strong> — 節點級別的代理程序 (virt-handler)</li></ol><h3 id="kubevirt-razor-設計準則" tabindex="-1">KubeVirt Razor（設計準則） <a class="header-anchor" href="#kubevirt-razor-設計準則" aria-label="Permalink to &quot;KubeVirt Razor（設計準則）&quot;">​</a></h3><blockquote><p><em>「如果某個功能對 Pod 也有用，我們就不應該只為 VM 實作它。」</em></p></blockquote><p>這個原則讓 KubeVirt 盡可能重用 Kubernetes 現有的基礎設施：</p><ul><li>網路使用 CNI、Multus 而非自行實作</li><li>儲存使用 PVC、StorageClass 而非自行管理</li><li>調度使用 kube-scheduler 而非另起爐灶</li><li>安全模型與 Pod 保持一致</li></ul><h2 id="技術棧" tabindex="-1">技術棧 <a class="header-anchor" href="#技術棧" aria-label="Permalink to &quot;技術棧&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│  KubeVirt (虛擬化 API)               │  ← 本文重點</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│  Orchestration (Kubernetes)          │  ← 調度、服務發現</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│  Scheduling (Kubernetes Scheduler)   │  ← Pod/VM 排程</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│  Container Runtime (containerd/CRI)  │  ← 容器執行環境</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│  Operating System (Linux)            │  ← 宿主機 OS</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│  Physical / Virtual Hardware         │  ← 實體或虛擬 CPU/記憶體</span></span>
<span class="line"><span>└─────────────────────────────────────┘</span></span></code></pre></div><h2 id="整體架構圖" tabindex="-1">整體架構圖 <a class="header-anchor" href="#整體架構圖" aria-label="Permalink to &quot;整體架構圖&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    ┌────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>                    │              Kubernetes API Server                  │</span></span>
<span class="line"><span>                    │  (儲存所有 CRD：VM, VMI, Migration, Snapshot...)   │</span></span>
<span class="line"><span>                    └──────────┬───────────────────┬──────────────────────┘</span></span>
<span class="line"><span>                               │ Watch/Update       │ Watch/Update</span></span>
<span class="line"><span>                               ▼                    ▼</span></span>
<span class="line"><span>              ┌────────────────────┐    ┌──────────────────────┐</span></span>
<span class="line"><span>              │    virt-api        │    │   virt-controller     │</span></span>
<span class="line"><span>              │  (Deployment × N)  │    │  (Deployment × N)     │</span></span>
<span class="line"><span>              │  ● REST API 入口    │    │  ● VM/VMI 控制器      │</span></span>
<span class="line"><span>              │  ● Admission Webhook│   │  ● Migration 控制器   │</span></span>
<span class="line"><span>              │  ● Console/VNC 代理 │   │  ● Snapshot 控制器    │</span></span>
<span class="line"><span>              └────────┬───────────┘    └─────────┬────────────┘</span></span>
<span class="line"><span>                       │                           │ 建立 Pod</span></span>
<span class="line"><span>                       │                           ▼</span></span>
<span class="line"><span>                       │              ┌─────────────────────────────┐</span></span>
<span class="line"><span>                       │              │    virt-launcher Pod (×VMI)  │</span></span>
<span class="line"><span>                       │              │  ┌─────────────────────────┐ │</span></span>
<span class="line"><span>                       │              │  │  virt-launcher 程序      │ │</span></span>
<span class="line"><span>                       │              │  │  (接收命令、轉發指令)     │ │</span></span>
<span class="line"><span>                       │              │  ├─────────────────────────┤ │</span></span>
<span class="line"><span>                       │              │  │  libvirtd + QEMU         │ │</span></span>
<span class="line"><span>                       │              │  │  (實際執行 VM)            │ │</span></span>
<span class="line"><span>                       │              │  └─────────────────────────┘ │</span></span>
<span class="line"><span>                       │              └──────────────────────────────┘</span></span>
<span class="line"><span>                       │                           ▲</span></span>
<span class="line"><span>                       │                           │ Unix Socket 通訊</span></span>
<span class="line"><span>                       │              ┌────────────┴────────────┐</span></span>
<span class="line"><span>                       └─────────────→│     virt-handler         │</span></span>
<span class="line"><span>                                      │   (DaemonSet per Node)   │</span></span>
<span class="line"><span>                                      │  ● 同步 VMI 狀態          │</span></span>
<span class="line"><span>                                      │  ● 呼叫 virt-launcher     │</span></span>
<span class="line"><span>                                      │  ● 管理網路/儲存           │</span></span>
<span class="line"><span>                                      └─────────────────────────┘</span></span>
<span class="line"><span>                                           ● 每個節點一個實例</span></span>
<span class="line"><span>                                           ● HostPID / HostNetwork</span></span></code></pre></div><h2 id="五大核心元件" tabindex="-1">五大核心元件 <a class="header-anchor" href="#五大核心元件" aria-label="Permalink to &quot;五大核心元件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>元件</th><th>部署型態</th><th>職責摘要</th></tr></thead><tbody><tr><td><strong><a href="/kubevirt-learning-site/components/virt-operator.html">virt-operator</a></strong></td><td>Deployment (≥2 副本)</td><td>安裝與管理所有 KubeVirt 元件，監控 <code>KubeVirt</code> CR</td></tr><tr><td><strong><a href="/kubevirt-learning-site/components/virt-api.html">virt-api</a></strong></td><td>Deployment (≥2 副本)</td><td>HTTP/WebSocket API 入口，Admission Webhook，console/VNC 代理</td></tr><tr><td><strong><a href="/kubevirt-learning-site/components/virt-controller.html">virt-controller</a></strong></td><td>Deployment (≥2 副本)</td><td>叢集級 VM 生命週期管理，建立/刪除 virt-launcher Pod</td></tr><tr><td><strong><a href="/kubevirt-learning-site/components/virt-handler.html">virt-handler</a></strong></td><td>DaemonSet (每節點一個)</td><td>節點代理，同步 VMI 與 libvirt domain，管理 migration</td></tr><tr><td><strong><a href="/kubevirt-learning-site/components/virt-launcher.html">virt-launcher</a></strong></td><td>Pod (每 VMI 一個)</td><td>提供 cgroups/namespaces 隔離，執行 libvirtd + QEMU</td></tr></tbody></table><h2 id="重要-crd-資源" tabindex="-1">重要 CRD 資源 <a class="header-anchor" href="#重要-crd-資源" aria-label="Permalink to &quot;重要 CRD 資源&quot;">​</a></h2><p>KubeVirt 為 Kubernetes 新增了以下 CRD：</p><h3 id="核心資源" tabindex="-1">核心資源 <a class="header-anchor" href="#核心資源" aria-label="Permalink to &quot;核心資源&quot;">​</a></h3><table tabindex="0"><thead><tr><th>CRD</th><th>說明</th></tr></thead><tbody><tr><td><code>VirtualMachine</code> (VM)</td><td><strong>有狀態 VM</strong> — 停止後資料保留，可重新啟動</td></tr><tr><td><code>VirtualMachineInstance</code> (VMI)</td><td><strong>執行中的 VM 實例</strong> — 暫態，關機後消失</td></tr><tr><td><code>VirtualMachineInstanceReplicaSet</code></td><td>VM 水平擴展 (類似 ReplicaSet)</td></tr><tr><td><code>VirtualMachinePool</code></td><td>高階 VM 池管理 (類似 Deployment)</td></tr><tr><td><code>VirtualMachineInstanceMigration</code></td><td>Live Migration 請求物件</td></tr></tbody></table><h3 id="進階資源" tabindex="-1">進階資源 <a class="header-anchor" href="#進階資源" aria-label="Permalink to &quot;進階資源&quot;">​</a></h3><table tabindex="0"><thead><tr><th>CRD</th><th>說明</th></tr></thead><tbody><tr><td><code>VirtualMachineInstancetype</code></td><td>CPU/記憶體規格模板 (namespace-scoped)</td></tr><tr><td><code>VirtualMachineClusterInstancetype</code></td><td>CPU/記憶體規格模板 (cluster-scoped)</td></tr><tr><td><code>VirtualMachinePreference</code></td><td>設備偏好配置</td></tr><tr><td><code>VirtualMachineSnapshot</code></td><td>VM 快照</td></tr><tr><td><code>VirtualMachineRestore</code></td><td>VM 還原請求</td></tr><tr><td><code>VirtualMachineClone</code></td><td>VM 克隆請求</td></tr><tr><td><code>VirtualMachineExport</code></td><td>VM 磁碟匯出</td></tr><tr><td><code>VirtualMachineBackup</code></td><td>VM 備份 (含增量備份)</td></tr><tr><td><code>KubeVirt</code></td><td>KubeVirt 安裝與設定 CR</td></tr></tbody></table><h2 id="與原生-kubernetes-的關係" tabindex="-1">與原生 Kubernetes 的關係 <a class="header-anchor" href="#與原生-kubernetes-的關係" aria-label="Permalink to &quot;與原生 Kubernetes 的關係&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Kubernetes 原生工作負載</span></span>
<span class="line"><span>    Pod ──── 由 kubelet 直接管理</span></span>
<span class="line"><span></span></span>
<span class="line"><span>KubeVirt 虛擬機工作負載</span></span>
<span class="line"><span>    VM ──→ VMI ──→ virt-launcher Pod ──→ libvirtd ──→ QEMU VM</span></span>
<span class="line"><span>           └── 由 virt-controller 建立 Pod</span></span>
<span class="line"><span>                   └── 由 virt-handler 透過 socket 管理</span></span></code></pre></div><p><strong>設計要點：</strong></p><ul><li>VM 對 Kubernetes 來說就是一個 Pod (virt-launcher)</li><li>Kubernetes 負責調度、網路、儲存的基礎</li><li>KubeVirt 在 Pod 內部管理 VM 的具體執行</li><li>同一 namespace 可以同時存在 Pod 和 VM，使用相同的 NetworkPolicy、RBAC</li></ul><h2 id="資料流-以建立-vm-為例" tabindex="-1">資料流：以建立 VM 為例 <a class="header-anchor" href="#資料流-以建立-vm-為例" aria-label="Permalink to &quot;資料流：以建立 VM 為例&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者執行：kubectl apply -f my-vm.yaml</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>1. [virt-api]</span></span>
<span class="line"><span>   ├── Mutating Webhook：補齊預設值</span></span>
<span class="line"><span>   ├── Validating Webhook：驗證 spec</span></span>
<span class="line"><span>   └── 寫入 VirtualMachine CR 到 API Server</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        │ watch</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>2. [virt-controller - VM 控制器]</span></span>
<span class="line"><span>   └── 建立 VirtualMachineInstance (VMI) CR</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        │ watch</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>3. [virt-controller - VMI 控制器]</span></span>
<span class="line"><span>   └── 建立 virt-launcher Pod (包含 libvirt)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        │ Kubernetes 調度</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>4. [kube-scheduler]</span></span>
<span class="line"><span>   └── 選定節點，kubelet 拉起 Pod</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        │ Pod Running</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>5. [virt-controller]</span></span>
<span class="line"><span>   └── 更新 VMI.spec.nodeName = 選定節點</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        │ watch (nodeName 改變)</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>6. [virt-handler (在目標節點上)]</span></span>
<span class="line"><span>   ├── 透過 Unix socket 呼叫 virt-launcher</span></span>
<span class="line"><span>   ├── 將 VMI spec 轉換為 libvirt domain XML</span></span>
<span class="line"><span>   └── 呼叫 libvirtd 啟動 QEMU 程序</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>7. [QEMU VM 開始執行]</span></span>
<span class="line"><span>   VM 狀態更新：Pending → Scheduling → Scheduled → Running</span></span></code></pre></div><h2 id="編排-vs-協作模式" tabindex="-1">編排 vs 協作模式 <a class="header-anchor" href="#編排-vs-協作模式" aria-label="Permalink to &quot;編排 vs 協作模式&quot;">​</a></h2><p>KubeVirt 使用<strong>協作 (Choreography)</strong> 模式，而非編排 (Orchestration) 模式：</p><ul><li>每個元件<strong>各自觀察</strong>狀態並採取行動</li><li>沒有中央指揮官，而是透過 <strong>VMI CR 作為共享狀態</strong></li><li>這讓系統更具彈性與可擴展性</li><li>類似於 Kubernetes 本身的 level-triggered 協調機制</li></ul><div class="tip custom-block"><p class="custom-block-title">類比</p><p>這就像交通規則 (協作)，而非由交通管制員指揮每輛車 (編排)。每個元件都知道自己的規則，並根據現狀自主行動。</p></div><h2 id="原始碼位置參考" tabindex="-1">原始碼位置參考 <a class="header-anchor" href="#原始碼位置參考" aria-label="Permalink to &quot;原始碼位置參考&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kubevirt/</span></span>
<span class="line"><span>├── cmd/                    # 各元件的 main.go 入口</span></span>
<span class="line"><span>│   ├── virt-api/</span></span>
<span class="line"><span>│   ├── virt-controller/</span></span>
<span class="line"><span>│   ├── virt-handler/</span></span>
<span class="line"><span>│   ├── virt-launcher/</span></span>
<span class="line"><span>│   └── virt-operator/</span></span>
<span class="line"><span>├── pkg/                    # 各元件的核心邏輯</span></span>
<span class="line"><span>│   ├── virt-api/</span></span>
<span class="line"><span>│   ├── virt-controller/</span></span>
<span class="line"><span>│   ├── virt-handler/</span></span>
<span class="line"><span>│   ├── virt-launcher/</span></span>
<span class="line"><span>│   └── virt-operator/</span></span>
<span class="line"><span>├── staging/src/kubevirt.io/</span></span>
<span class="line"><span>│   └── api/                # 所有 CRD 型別定義</span></span>
<span class="line"><span>│       ├── core/v1/        # VM, VMI, KubeVirt 等</span></span>
<span class="line"><span>│       ├── instancetype/   # Instancetype, Preference</span></span>
<span class="line"><span>│       ├── snapshot/       # VirtualMachineSnapshot</span></span>
<span class="line"><span>│       ├── clone/          # VirtualMachineClone</span></span>
<span class="line"><span>│       ├── export/         # VirtualMachineExport</span></span>
<span class="line"><span>│       └── backup/         # VirtualMachineBackup</span></span>
<span class="line"><span>└── docs/                   # 官方文件</span></span></code></pre></div>`,34)])])}const b=a(t,[["render",l]]);export{u as __pageData,b as default};
